// AC #3 (exponential backoff fallback) end-to-end.
func TestRunWithRateLimitRetry_ExponentialBackoffWhenRetryAfterAbsent(t *testing.T) {
	var sleepCalls []time.Duration
	cfg := RateLimitRetryConfig{
		Budget:     5 * time.Minute,
