// appendRateLimitRetryEvent records one rate-limit retry on the bead's
// event stream per TD-031 §4 / §8.4 RateLimitRetryContract. The event body
// carries the retry count and wait duration so an audit can reconstruct the
// pause without consulting routing logs.
func appendRateLimitRetryEvent(appender BeadEventAppender, beadID string, info RateLimitRetryInfo) {
	if appender == nil || beadID == "" {
		return
	}
	body := map[string]any{
		"attempt":     info.Attempt,
		"wait_ms":     info.Wait.Milliseconds(),
		"source":      info.Source,
		"elapsed_ms":  info.Elapsed.Milliseconds(),
		"over_budget": info.OverBudget,
	}
	if info.Result != nil {
		if info.Result.Harness != "" {
			body["harness"] = info.Result.Harness
		}
		if info.Result.Provider != "" {
			body["provider"] = info.Result.Provider
		}
		if info.Result.Model != "" {
			body["model"] = info.Result.Model
		}
	}
	data, err := json.Marshal(body)
	if err != nil {
		return
	}
	summary := fmt.Sprintf("attempt=%d wait=%s source=%s", info.Attempt, info.Wait.Round(time.Millisecond), info.Source)
	if info.OverBudget {
		summary = "budget exhausted: " + RateLimitBudgetExhaustedReason
	}
	_ = appender.AppendEvent(beadID, bead.BeadEvent{
		Kind:    RateLimitRetryEventKind,
		Summary: summary,
		Body:    string(data),
		Actor:   "ddx",
		Source:  "legacy agent execute-bead",
	})
}

// ExecuteBeadWithConfig is the thin worker: it creates an isolated attempt workspace,
// constructs the agent prompt from bead context, runs the agent harness,
// synthesizes a commit if the agent left uncommitted changes, then cleans up
// the workspace and returns the result. It classifies outcomes as exactly one
// of:
//
//   - task_succeeded: agent exited 0 and produced one or more commits
//   - task_failed:    agent exited non-zero
//   - task_no_changes: agent exited 0, made no commits, and wrote a rationale
//   - task_no_evidence: agent exited 0 but made no commits and wrote no rationale
//
// Merge, UpdateRef, gate evaluation, preserve-ref management, and orphan
// recovery are the parent's responsibility (see LandBeadResult, RecoverOrphans).
//

package agent

import (
	"context"
	"strings"
	"time"

	agentlib "github.com/easel/fizeau"
	"github.com/DocumentDrivenDX/ddx/internal/ratelimitpolicy"
)

// RateLimitRetryDefaultBudget is the default per-bead total wait budget for
// rate-limit retries. AC #4 of ddx-c6e3db02 names 5 minutes.
const RateLimitRetryDefaultBudget = ratelimitpolicy.RateLimitRetryDefaultBudget

// RateLimitRetryDefaultPerWaitCap caps any single retry wait so a misbehaving
// provider cannot pin the worker with a one-hour Retry-After. The bead
// description names 60 seconds as the per-wait cap.
const RateLimitRetryDefaultPerWaitCap = ratelimitpolicy.RateLimitRetryDefaultPerWaitCap

// RateLimitBudgetExhaustedReason is the canonical reason string written into
// Result.Error when the per-bead retry budget is exhausted. The execute-bead
// status mapping translates this into FailureModeAuthError so it surfaces in
// the standard execution_failed pathway (TD-031 §8.4).
const RateLimitBudgetExhaustedReason = ratelimitpolicy.RateLimitBudgetExhaustedReason

// RateLimitRetryEventKind is the bead event kind appended on each retry per
// TD-031 §4 / §8.4 RateLimitRetryContract. The body carries the retry count
// and wait duration.
const RateLimitRetryEventKind = "rate-limit-retry"

type RateLimitWaitDecision = ratelimitpolicy.RateLimitWaitDecision
type RateLimitRetryInfo = ratelimitpolicy.RateLimitRetryInfo[*Result]
type RateLimitRetryConfig = ratelimitpolicy.RateLimitRetryConfig[*Result]

func EvaluateRateLimitWait(retryAfter time.Duration, attempt int, elapsed, budget, perWaitCap time.Duration) RateLimitWaitDecision {
	return ratelimitpolicy.EvaluateRateLimitWait(retryAfter, attempt, elapsed, budget, perWaitCap)
}

func IsRateLimitResult(result *Result) bool {
	if result == nil {
		return false
	}
	combined := strings.ToLower(result.Error + "\n" + result.Stderr)
	if combined == "\n" {
		return false
	}
	return ratelimitpolicy.IsRateLimitText(combined)
}

func ParseRetryAfter(value string, now time.Time) time.Duration {
	return ratelimitpolicy.ParseRetryAfter(value, now)
}

func ExtractRetryAfterFromStderr(stderr string, now time.Time) time.Duration {
	return ratelimitpolicy.ExtractRetryAfterFromStderr(stderr, now)
}

// RunWithRateLimitRetry invokes attempt and, when its result is a rate-limit
// signal per IsRateLimitResult, waits per EvaluateRateLimitWait and retries
// until either attempt returns a non-rate-limit result or the per-bead budget
// is exhausted. Budget exhaustion mutates the final result's Error to
// RateLimitBudgetExhaustedReason and returns it without further retries.
//
// The wrapper does NOT change provider availability state — the provider
// stays in rotation per AC #2 of ddx-c6e3db02. Per AC #6, callers wire
// RecordRouteAttempt via OnRetry for transparency.
func RunWithRateLimitRetry(ctx context.Context, cfg RateLimitRetryConfig, attempt func(ctx context.Context) (*Result, error)) (*Result, error) {
	if cfg.Budget < 0 {
		// Negative budget disables the wrapper entirely (parity with
		// "feature off"). Useful for tests and operator opt-out.
		return attempt(ctx)
	}
	cfg = ratelimitpolicy.ResolveRateLimitRetryConfig(cfg)

	var (
		elapsed    time.Duration
		retryCount int
	)
	for {
		res, err := attempt(ctx)
		if err != nil || res == nil {
			return res, err
		}
		if !IsRateLimitResult(res) {
			return res, nil
		}

		retryCount++
		retryAfter := ExtractRetryAfterFromStderr(res.Stderr, cfg.Now())
		decision := EvaluateRateLimitWait(retryAfter, retryCount, elapsed, cfg.Budget, cfg.PerWaitCap)
		if !decision.ShouldRetry {
			// Budget exhausted: surface the canonical reason so the standard
			// execution_failed mapping fires (TD-031 §5).
			res.Error = RateLimitBudgetExhaustedReason
			if cfg.OnRetry != nil {
				cfg.OnRetry(ctx, RateLimitRetryInfo{
					Attempt:    retryCount,
					Source:     decision.Source,
					Payload:    res,
					Elapsed:    elapsed,
					OverBudget: true,
				})
			}
			return res, nil
		}

		if cfg.OnRetry != nil {
			cfg.OnRetry(ctx, RateLimitRetryInfo{
				Attempt: retryCount,
				Wait:    decision.Wait,
				Source:  decision.Source,
				Payload: res,
				Elapsed: elapsed,
			})
		}

		if err := cfg.Sleep(ctx, decision.Wait); err != nil {
			return res, err
		}
		elapsed += decision.Wait
	}
}

// BuildRateLimitRouteAttempt constructs a fizeau.RouteAttempt that records a
// rate-limit retry on the routing-engine feedback channel. The Status is
// "rate_limited" so the engine has signal even though provider availability
// remains unchanged per RateLimitRetryContract.
func BuildRateLimitRouteAttempt(info RateLimitRetryInfo) agentlib.RouteAttempt {
	att := agentlib.RouteAttempt{
		Status:    "rate_limited",
		Reason:    info.Source,
		Duration:  info.Wait,
		Timestamp: time.Now().UTC(),
	}
	if info.Result != nil {
	if info.Payload != nil {
		att.Harness = info.Payload.Harness
		att.Provider = info.Payload.Provider
		att.Model = info.Payload.Model
		att.Error = info.Payload.Error
	}
	if info.OverBudget {
		att.Reason = RateLimitBudgetExhaustedReason
	}
	return att
}

